@pytest.mark.asyncio
async def test_auth_basic_http() -> None:
    """Sends HTTP Basic authentication header."""
    engine_config = CrawlConfig(
        auth={"password": "testpass", "type": "basic", "username": "testuser"},
        respect_robots_txt=False,
    )
